//! Lockfile management for reproducible builds (ADR 0070 Phase 1).
//!
//! **DDD Context:** Build System
//!
//! The lockfile (`beamtalk.lock`) pins exact commit SHAs for git dependencies.
//! Path dependencies are intentionally NOT locked — they resolve to whatever
//! is on disk, so they are only reproducible within a single checkout.
//!
//! ## Format
//!
//! The lockfile uses a simple, human-readable, git-friendly format:
//!
//! ```text
//! # This file is auto-generated by beamtalk. Do not edit manually.
//! # It pins exact versions of git dependencies for reproducible builds.
//!
//! [[package]]
//! name = "json"
//! url = "https://github.com/jamesc/beamtalk-json"
//! reference = "tag:v1.0.0"
//! sha = "abc1234def5678..."
//!
//! [[package]]
//! name = "http"
//! url = "https://github.com/someone/beamtalk-http"
//! reference = "branch:main"
//! sha = "fed8765cba4321..."
//! ```

use beamtalk_core::compilation::GitReference;
use camino::Utf8Path;
use miette::{Context, IntoDiagnostic, Result};
use serde::{Deserialize, Serialize};
use std::collections::BTreeMap;
use std::fmt::Write as _;

/// The lockfile filename.
#[allow(dead_code)] // Used by tests; will be called by build system (ADR 0070 Phase 2+)
pub const LOCKFILE_NAME: &str = "beamtalk.lock";

/// The lockfile header comment.
#[allow(dead_code)] // Called by Lockfile::serialize (ADR 0070 Phase 2+)
const LOCKFILE_HEADER: &str = "\
# This file is auto-generated by beamtalk. Do not edit manually.
# It pins exact versions of git dependencies for reproducible builds.
";

/// A single locked dependency entry.
#[derive(Debug, Clone, PartialEq, Eq)]
#[allow(dead_code)] // Used by tests; will be called by build system (ADR 0070 Phase 2+)
pub struct LockEntry {
    /// The dependency name.
    pub name: String,
    /// The git repository URL.
    pub url: String,
    /// The requested reference (tag/branch/rev from `beamtalk.toml`).
    pub reference: GitReference,
    /// The exact commit SHA this reference resolved to.
    pub resolved_sha: String,
}

/// The full lockfile contents — an ordered collection of lock entries.
#[derive(Debug, Clone, PartialEq, Eq)]
#[allow(dead_code)] // Used by tests; will be called by build system (ADR 0070 Phase 2+)
pub struct Lockfile {
    /// Locked packages, keyed by dependency name.
    pub packages: BTreeMap<String, LockEntry>,
}

/// Intermediate TOML representation for serialization.
#[derive(Debug, Serialize, Deserialize)]
#[allow(dead_code)] // Constructed by serde deserialization
struct TomlLockfile {
    #[serde(default)]
    package: Vec<TomlLockEntry>,
}

/// A single package entry in the TOML lockfile.
#[derive(Debug, Serialize, Deserialize)]
#[allow(dead_code)] // Constructed by serde deserialization
struct TomlLockEntry {
    name: String,
    url: String,
    reference: String,
    sha: String,
}

#[allow(dead_code)] // Used by tests; will be called by build system (ADR 0070 Phase 2+)
impl Lockfile {
    /// Create an empty lockfile.
    pub fn new() -> Self {
        Self {
            packages: BTreeMap::new(),
        }
    }

    /// Add or update a lock entry.
    pub fn insert(&mut self, entry: LockEntry) {
        self.packages.insert(entry.name.clone(), entry);
    }

    /// Look up a lock entry by dependency name.
    pub fn get(&self, name: &str) -> Option<&LockEntry> {
        self.packages.get(name)
    }

    /// Returns `true` if the lockfile contains no entries.
    pub fn is_empty(&self) -> bool {
        self.packages.is_empty()
    }

    /// Read a lockfile from disk.
    ///
    /// Returns `None` if the file does not exist. Returns an error if the
    /// file exists but cannot be parsed.
    pub fn read(project_root: &Utf8Path) -> Result<Option<Self>> {
        let path = project_root.join(LOCKFILE_NAME);
        if !path.exists() {
            return Ok(None);
        }

        let content = std::fs::read_to_string(&path)
            .into_diagnostic()
            .wrap_err_with(|| format!("Failed to read lockfile '{path}'"))?;

        let lockfile =
            Self::parse(&content).wrap_err_with(|| format!("Failed to parse lockfile '{path}'"))?;

        Ok(Some(lockfile))
    }

    /// Parse lockfile content from a string.
    pub fn parse(content: &str) -> Result<Self> {
        let toml_lock: TomlLockfile = toml::from_str(content)
            .into_diagnostic()
            .wrap_err("Invalid lockfile format")?;

        let mut packages = BTreeMap::new();
        for entry in toml_lock.package {
            let reference = parse_reference(&entry.reference).wrap_err_with(|| {
                format!(
                    "Invalid reference '{}' for package '{}'",
                    entry.reference, entry.name
                )
            })?;

            packages.insert(
                entry.name.clone(),
                LockEntry {
                    name: entry.name,
                    url: entry.url,
                    reference,
                    resolved_sha: entry.sha,
                },
            );
        }

        Ok(Self { packages })
    }

    /// Write the lockfile to disk.
    ///
    /// If the lockfile has no entries (no git deps), the file is removed
    /// to keep the project directory clean.
    pub fn write(&self, project_root: &Utf8Path) -> Result<()> {
        let path = project_root.join(LOCKFILE_NAME);

        if self.is_empty() {
            // Remove stale lockfile if no git deps
            if path.exists() {
                std::fs::remove_file(&path)
                    .into_diagnostic()
                    .wrap_err_with(|| format!("Failed to remove empty lockfile '{path}'"))?;
            }
            return Ok(());
        }

        let content = self.serialize();
        std::fs::write(&path, content)
            .into_diagnostic()
            .wrap_err_with(|| format!("Failed to write lockfile '{path}'"))?;

        Ok(())
    }

    /// Serialize the lockfile to a string.
    pub fn serialize(&self) -> String {
        let mut output = String::new();
        output.push_str(LOCKFILE_HEADER);
        output.push('\n');

        for entry in self.packages.values() {
            output.push_str("[[package]]\n");
            let _ = writeln!(output, "name = \"{}\"", entry.name);
            let _ = writeln!(output, "url = \"{}\"", entry.url);
            let _ = writeln!(
                output,
                "reference = \"{}\"",
                format_reference(&entry.reference)
            );
            let _ = writeln!(output, "sha = \"{}\"", entry.resolved_sha);
            output.push('\n');
        }

        output
    }
}

impl Default for Lockfile {
    fn default() -> Self {
        Self::new()
    }
}

/// Format a `GitReference` for lockfile storage.
///
/// Uses `type:value` format: `tag:v1.0.0`, `branch:main`, `rev:abc1234`.
#[allow(dead_code)] // Called by Lockfile::serialize (ADR 0070 Phase 2+)
fn format_reference(reference: &GitReference) -> String {
    match reference {
        GitReference::Tag(tag) => format!("tag:{tag}"),
        GitReference::Branch(branch) => format!("branch:{branch}"),
        GitReference::Rev(rev) => format!("rev:{rev}"),
    }
}

/// Parse a lockfile reference string back to a `GitReference`.
#[allow(dead_code)] // Called by Lockfile::parse (ADR 0070 Phase 2+)
fn parse_reference(s: &str) -> Result<GitReference> {
    if let Some(tag) = s.strip_prefix("tag:") {
        Ok(GitReference::Tag(tag.to_string()))
    } else if let Some(branch) = s.strip_prefix("branch:") {
        Ok(GitReference::Branch(branch.to_string()))
    } else if let Some(rev) = s.strip_prefix("rev:") {
        Ok(GitReference::Rev(rev.to_string()))
    } else {
        miette::bail!(
            "Invalid reference format '{s}' — expected 'tag:...', 'branch:...', or 'rev:...'"
        );
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    fn sample_lockfile() -> Lockfile {
        let mut lockfile = Lockfile::new();
        lockfile.insert(LockEntry {
            name: "http".to_string(),
            url: "https://github.com/someone/beamtalk-http".to_string(),
            reference: GitReference::Branch("main".to_string()),
            resolved_sha: "fed8765cba4321fed8765cba4321fed8765cba43".to_string(),
        });
        lockfile.insert(LockEntry {
            name: "json".to_string(),
            url: "https://github.com/jamesc/beamtalk-json".to_string(),
            reference: GitReference::Tag("v1.0.0".to_string()),
            resolved_sha: "abc1234def5678abc1234def5678abc1234def56".to_string(),
        });
        lockfile
    }

    #[test]
    fn test_serialize_lockfile() {
        let lockfile = sample_lockfile();
        let content = lockfile.serialize();

        assert!(content.contains("# This file is auto-generated by beamtalk"));
        assert!(content.contains("[[package]]"));
        assert!(content.contains("name = \"json\""));
        assert!(content.contains("reference = \"tag:v1.0.0\""));
        assert!(content.contains("name = \"http\""));
        assert!(content.contains("reference = \"branch:main\""));
    }

    #[test]
    fn test_roundtrip_lockfile() {
        let original = sample_lockfile();
        let serialized = original.serialize();
        let parsed = Lockfile::parse(&serialized).unwrap();

        assert_eq!(original, parsed);
    }

    #[test]
    fn test_parse_lockfile_with_rev() {
        let content = r#"
[[package]]
name = "tools"
url = "https://github.com/someone/beamtalk-tools"
reference = "rev:abc1234"
sha = "abc1234def5678abc1234def5678abc1234def56"
"#;

        let lockfile = Lockfile::parse(content).unwrap();
        assert_eq!(lockfile.packages.len(), 1);
        let entry = lockfile.get("tools").unwrap();
        assert_eq!(entry.reference, GitReference::Rev("abc1234".to_string()));
    }

    #[test]
    fn test_parse_empty_lockfile() {
        // A lockfile with just comments and no packages is valid
        let content = "# Empty lockfile\n";
        let lockfile = Lockfile::parse(content).unwrap();
        assert!(lockfile.is_empty());
    }

    #[test]
    fn test_parse_invalid_reference() {
        let content = r#"
[[package]]
name = "bad"
url = "https://example.com/bad"
reference = "invalid_format"
sha = "abc123"
"#;

        let result = Lockfile::parse(content);
        assert!(result.is_err());
        let err = format!("{:?}", result.unwrap_err());
        assert!(
            err.contains("Invalid reference"),
            "Should mention invalid reference: {err}"
        );
    }

    #[test]
    fn test_write_and_read_lockfile() {
        let temp = TempDir::new().unwrap();
        let project_root = camino::Utf8PathBuf::from_path_buf(temp.path().to_path_buf()).unwrap();

        let lockfile = sample_lockfile();
        lockfile.write(&project_root).unwrap();

        // Verify the file was written
        let lock_path = project_root.join(LOCKFILE_NAME);
        assert!(lock_path.exists());

        // Read it back
        let read_back = Lockfile::read(&project_root).unwrap().unwrap();
        assert_eq!(lockfile, read_back);
    }

    #[test]
    fn test_read_nonexistent_lockfile() {
        let temp = TempDir::new().unwrap();
        let project_root = camino::Utf8PathBuf::from_path_buf(temp.path().to_path_buf()).unwrap();

        let result = Lockfile::read(&project_root).unwrap();
        assert!(result.is_none());
    }

    #[test]
    fn test_empty_lockfile_removes_file() {
        let temp = TempDir::new().unwrap();
        let project_root = camino::Utf8PathBuf::from_path_buf(temp.path().to_path_buf()).unwrap();

        // Write a lockfile first
        let lockfile = sample_lockfile();
        lockfile.write(&project_root).unwrap();
        assert!(project_root.join(LOCKFILE_NAME).exists());

        // Writing an empty lockfile should remove the file
        let empty = Lockfile::new();
        empty.write(&project_root).unwrap();
        assert!(!project_root.join(LOCKFILE_NAME).exists());
    }

    #[test]
    fn test_lockfile_is_sorted_by_name() {
        let mut lockfile = Lockfile::new();
        // Insert in reverse order
        lockfile.insert(LockEntry {
            name: "zebra".to_string(),
            url: "https://example.com/zebra".to_string(),
            reference: GitReference::Tag("v1".to_string()),
            resolved_sha: "aaa".to_string(),
        });
        lockfile.insert(LockEntry {
            name: "alpha".to_string(),
            url: "https://example.com/alpha".to_string(),
            reference: GitReference::Tag("v1".to_string()),
            resolved_sha: "bbb".to_string(),
        });

        let serialized = lockfile.serialize();
        let alpha_pos = serialized.find("name = \"alpha\"").unwrap();
        let zebra_pos = serialized.find("name = \"zebra\"").unwrap();
        assert!(
            alpha_pos < zebra_pos,
            "Packages should be sorted alphabetically"
        );
    }

    #[test]
    fn test_lockfile_git_friendly_format() {
        let lockfile = sample_lockfile();
        let content = lockfile.serialize();

        // Each entry should be on its own line (git-friendly)
        for line in content.lines() {
            // No line should be excessively long
            assert!(
                line.len() < 200,
                "Lines should be short for git friendliness: {line}"
            );
        }

        // Entries should be separated by blank lines
        assert!(
            content.contains("\n\n[[package]]"),
            "Entries should be separated by blank lines"
        );
    }

    #[test]
    fn test_insert_overwrites_existing() {
        let mut lockfile = Lockfile::new();
        lockfile.insert(LockEntry {
            name: "dep".to_string(),
            url: "https://example.com/dep".to_string(),
            reference: GitReference::Tag("v1".to_string()),
            resolved_sha: "old_sha".to_string(),
        });
        lockfile.insert(LockEntry {
            name: "dep".to_string(),
            url: "https://example.com/dep".to_string(),
            reference: GitReference::Tag("v2".to_string()),
            resolved_sha: "new_sha".to_string(),
        });

        assert_eq!(lockfile.packages.len(), 1);
        assert_eq!(lockfile.get("dep").unwrap().resolved_sha, "new_sha");
    }
}
